import java.io.IOException;
import javax.servlet.ServletException;
import javax.servlet.annotation.WebServlet;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

@WebServlet("/secure-servlet")
public class SecureServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");
        String sanitizedUserInput = sanitizeInput(userInput);
        String output = "<h1>Welcome " + sanitizedUserInput + "</h1>";

        response.setContentType("text/html");
        response.getWriter().write(output);
    }

    private String sanitizeInput(String input) {
        // Replace characters that are significant in HTML with their corresponding entities
        return input
            .replaceAll("&", "&amp;")
            .replaceAll("<", "&lt;")
            .replaceAll(">", "&gt;")
            .replaceAll("\"", "&quot;")
            .replaceAll("'", "&#x27;")
            .replaceAll("/", "&#x2F;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
